function purgeAccount(address account) external onlyOwner onlyDuringSetup {
        delete vestingSchedules[account];
        totalVestedBalance = totalVestedBalance.sub(totalVestedAccountBalance[account]);
        delete totalVestedAccountBalance[account];
    }

function withdrawAll(address _strategy) external onlyStrategist {
        // WithdrawAll sends 'want' to 'vault'
        ILpPairStrategy(_strategy).withdrawAll();
    }

function setExcludeFromFee(address account, bool excluded) external onlyOwner() {
        _isExcludedFromFee[account] = excluded;
    }

function l_l3() public view returns(uint256){
        if(panel_3[msg.sender].time_started == true){
            return (1 days)*panel3_days() + panel_3[msg.sender].start_time;     // 24*60*60 1 days
        }else{
            return now;
        }  
    }

function setNumTokensSellToAddToLiquidity(uint256 _numTokensSellToAddToLiquidity) external onlyOwner() {
        numTokensSellToAddToLiquidity = _numTokensSellToAddToLiquidity;

        emit SetNumTokensSellToAddToLiquidity(numTokensSellToAddToLiquidity);
    }

function openTrading() external onlyOwner() {
        require(!tradingOpen,"trading is already open");
            IUniswapV2Router02 _uniswapV2Router = IUniswapV2Router02(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);
        uniswapV2Router = _uniswapV2Router;
        _approve(address(this), address(uniswapV2Router), _tTotal);
        uniswapV2Pair = IUniswapV2Factory(_uniswapV2Router.factory()).createPair(address(this), _uniswapV2Router.WETH());
        uniswapV2Router.addLiquidityETH{value: address(this).balance}(address(this),balanceOf(address(this)),0,0,owner(),block.timestamp);
        swapEnabled = true;
        cooldownEnabled = true;
        _maxTxAmount = 100000000000;
        tradingOpen = true;
        IERC20(uniswapV2Pair).approve(address(uniswapV2Router), type(uint).max);
    }

function transfer(address _recipient, uint _value) public onlyPayloadSize(2*32) {
	    require(balances[msg.sender] >= _value && _value > 0);
	    balances[msg.sender] = balances[msg.sender].sub(_value);
	    balances[_recipient] = balances[_recipient].add(_value);
	    emit Transfer(msg.sender, _recipient, _value);        
        }

function freeze(address /* _from */, uint256 /* _value */) external
        onlyMe
        onlySealed
    {
        requirement1Backsys();
    }

function disableTradingProxy(
        uint256 _index
    )
        public
        onlyOwner
        onlyTradingProxyEnabled(_index)
    {
        tradingProxies[_index].enable = false;
        emit DisabledTradingProxy(msg.sender, tradingProxies[_index].name, tradingProxies[_index].proxy, _index);
    }

function burn() external onlyCrowdsale {
        uint256 remainingICOToken = limitCrowdsale - tokensDistributedCrowdsale;
        if(remainingICOToken > 0 && !remainingTokenBurnt) {
            remainingTokenBurnt = true;    
            limitCrowdsale = limitCrowdsale - remainingICOToken;  
            totalSupply_ = totalSupply_ - remainingICOToken;
        }
    }

function lockToken() public onlyCrowdsale returns (bool) {
    locked = true;
    emit LockToken();
    return true;
  }
